(function () {
const toggle = document.getElementById('js-menu-toggle');
const closeBtn = document.getElementById('js-menu-close');
const menu = document.getElementById('js-menu');
if (!toggle || !menu) return;
const setOpen = (open) => {
menu.classList.toggle('is-open', open);
toggle.classList.toggle('is-open', open);
toggle.setAttribute('aria-expanded', open ? 'true' : 'false');
toggle.setAttribute('aria-label', open ? 'メニューを閉じる' : 'メニューを開く');
menu.setAttribute('aria-hidden', open ? 'false' : 'true');
document.body.classList.toggle('menu-open', open);
};
toggle.addEventListener('click', () => {
setOpen(!menu.classList.contains('is-open'));
});
if (closeBtn) {
closeBtn.addEventListener('click', () => setOpen(false));
}
menu.querySelectorAll('a').forEach((link) => {
link.addEventListener('click', () => setOpen(false));
});
document.addEventListener('keydown', (e) => {
if (e.key === 'Escape' && menu.classList.contains('is-open')) {
setOpen(false);
}
});
})();
(function () {
const setup = (videoId, title) => {
const video = document.getElementById(videoId);
if (!video) return;
const play = () => {
if (video.classList.contains('is-playing')) return;
const id = video.dataset.yt;
const iframe = document.createElement('iframe');
iframe.src = `https://www.youtube.com/embed/${id}?autoplay=1&rel=0&playsinline=1`;
iframe.title = title;
iframe.allow = 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share';
iframe.allowFullscreen = true;
video.appendChild(iframe);
video.classList.add('is-playing');
};
video.addEventListener('click', play);
video.addEventListener('keydown', (e) => {
if (e.key === 'Enter' || e.key === ' ') {
e.preventDefault();
play();
}
});
};
setup('js-about-video', 'トリイク サービス紹介ムービー');
setup('js-how-to-video', 'トリイク 使い方ムービー');
})();
(function () {
const scroller = document.getElementById('js-features-scroller');
const dotsWrap = document.getElementById('js-features-dots');
if (!scroller || !dotsWrap) return;
const dots = Array.from(dotsWrap.querySelectorAll('.features-dot'));
const cards = Array.from(scroller.children);
if (!cards.length) return;
const update = () => {
const center = scroller.scrollLeft + scroller.clientWidth / 2;
let idx = 0;
let best = Infinity;
cards.forEach((card, i) => {
const c = card.offsetLeft + card.offsetWidth / 2;
const d = Math.abs(c - center);
if (d < best) { best = d; idx = i; }
});
dots.forEach((d, i) => d.classList.toggle('is-active', i === idx));
};
let raf = 0;
scroller.addEventListener('scroll', () => {
cancelAnimationFrame(raf);
raf = requestAnimationFrame(update);
}, { passive: true });
dots.forEach((dot, i) => {
dot.addEventListener('click', () => {
cards[i].scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' });
});
});
})();
